mapper.select:
SELECT

FROM check_item_appeals a
LEFT JOIN users u ON COALESCE(a.appealer_id, a.appellant_id) = u.id
WHERE a.class_id = #{classId}
ORDER BY a.created_at DESC

    LIMIT #{limit}

SELECT
status,
COUNT(*) as count,
COALESCE(SUM(score_change), 0) as total_score_change,
COALESCE(AVG(score_change), 0) as avg_score_change
FROM check_item_appeals

    1=1

        AND grade_id = #{gradeId}


        AND class_id = #{classId}


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}


GROUP BY status

SELECT
appeal_type,
COUNT(*) as count,
SUM(CASE WHEN status = 2 THEN 1 ELSE 0 END) as approved_count,
SUM(CASE WHEN status = 3 THEN 1 ELSE 0 END) as rejected_count
FROM check_item_appeals

    1=1

        AND grade_id = #{gradeId}


        AND class_id = #{classId}


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}


GROUP BY appeal_type

SELECT
COUNT(*) as total_count,
SUM(CASE WHEN r.approval_status = 2 THEN 1 ELSE 0 END) as approved_count,
SUM(CASE WHEN r.approval_status = 3 THEN 1 ELSE 0 END) as rejected_count,
AVG(TIMESTAMPDIFF(HOUR, r.received_time, r.approval_time)) as avg_hours
FROM appeal_approval_records r
WHERE r.approver_id = #{approverId}
AND r.approval_status IN (2, 3)

    AND r.approval_time >= #{startTime}


    AND r.approval_time <= #{endTime}

SELECT COUNT(*)
FROM check_item_appeals
WHERE item_id = #{itemId}

    AND status NOT IN

        #{status}

SELECT
    COUNT(*) as totalCount,
    SUM(CASE WHEN status = 2 THEN 1 ELSE 0 END) as approvedCount,
    COALESCE(SUM(CASE WHEN status = 2 THEN ABS(score_change) ELSE 0 END), 0) as totalScoreAdjustment
FROM check_item_appeals
WHERE grade_id = #{gradeId}

    AND created_at >= #{startTime}


    AND created_at <= #{endTime}
